--- src/conda.ts
+++ src/conda.ts
@@ -1,5 +1,7 @@
 // ... existing code ...

+const getCondaEnvSubcommands: Fig.Generator = {
+  script: "conda env --help",
+  postProcess: function (out) {
+    const lines = out.split("\n");
+    const subcommands = [];
+    for (let i = 0; i < lines.length; i++) {
+      if (lines[i].startsWith("  ")) {
+        var subcommand = lines[i].trim().split(" ")[0];
+        subcommands.push({
+          name: subcommand,
+          icon: "🐍",
+        });
+      }
+    }
+    return subcommands;
+  },
+};
+
 const getCondaEnvironments: Fig.Generator = {
   script: "conda env list",
   scriptTimeout: 10000,
@@ -1087,3 +1091,10 @@
 // ... existing code ...

 const completionSpec: Fig.Spec = {
+  subcommands: [
+    {
+      name: "env",
+      description: "Environment management",
+      subcommands: getCondaEnvSubcommands,
+      options: [
+        {
+          name: "remove",
+          description: "Remove an environment",
+          args: {
+            name: "environment name",
+            generators: getCondaEnvironments,
+          },
+        },
+      ],
+    },
+  ],
 };
